/**
 * Animation Registry — Complete catalog of all animations available
 * from Quaternius character models.
 *
 * Auto-generated by scanning GLB/GLTF files in:
 *   client/public/assets/models/characters/quaternius/
 *
 * Three animation sources:
 *   - anim_ual1_standard (45 animations) — primary locomotion/action pack
 *   - anim2_ual2_standard (43 animations) — combat/farming/zombie pack
 *   - char_* models (24 animations each) — embedded character animations
 */

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export type AnimationCategory =
  | 'locomotion'
  | 'social'
  | 'work'
  | 'leisure'
  | 'combat'
  | 'emote'
  | 'activity'
  | 'pose'
  | 'ranged'
  | 'magic';

export interface AnimationEntry {
  name: string;
  description: string;
  duration: number;
  loop: boolean;
  category: AnimationCategory;
}

// ---------------------------------------------------------------------------
// Model IDs — every model directory that contains at least one animation
// ---------------------------------------------------------------------------

