const MODEL_ANIMATION_MAP: Record<ModelId, readonly string[]> = {
  ...charModelEntries,
  anim_ual1_standard: UAL1_ANIMATIONS,
  anim2_ual2_standard: UAL2_ANIMATIONS,
};

// ---------------------------------------------------------------------------
// Lookup functions
// ---------------------------------------------------------------------------

export function getAvailableAnimations(modelId: string): string[] {
  const anims = MODEL_ANIMATION_MAP[modelId as ModelId];
  return anims ? [...anims] : [];
}

export function getModelsWithAnimation(animationName: string): string[] {
  return ALL_MODEL_IDS.filter(id => {
    const anims = MODEL_ANIMATION_MAP[id];
    return anims.some(a => a === animationName);
  });
}

export function getAnimationsByCategory(category: AnimationCategory): AnimationEntry[] {
  return Object.values(ANIMATION_CATALOG).filter(e => e.category === category);
}

// ---------------------------------------------------------------------------
// Summary — call logAnimationSummary() to print audit results
// ---------------------------------------------------------------------------

export function getAnimationSummary(): {
  totalUniqueAnimations: number;
  categoryCounts: Record<string, number>;
  modelAnimationCounts: Record<string, number>;
  richestModels: { modelId: string; count: number }[];
} {
  const categoryCounts: Record<string, number> = {};
  for (const entry of Object.values(ANIMATION_CATALOG)) {
    categoryCounts[entry.category] = (categoryCounts[entry.category] || 0) + 1;
  }

  const modelAnimationCounts: Record<string, number> = {};
  for (const id of ALL_MODEL_IDS) {
    modelAnimationCounts[id] = MODEL_ANIMATION_MAP[id].length;
  }

  const richestModels = ALL_MODEL_IDS
    .map(id => ({ modelId: id, count: MODEL_ANIMATION_MAP[id].length }))
    .sort((a, b) => b.count - a.count);

  return {
    totalUniqueAnimations: Object.keys(ANIMATION_CATALOG).length,
    categoryCounts,
    modelAnimationCounts,
    richestModels,
  };
}

export function logAnimationSummary(): void {
  const summary = getAnimationSummary();
  for (const [cat, count] of Object.entries(summary.categoryCounts).sort((a, b) => b[1] - a[1])) {
  }
  for (const { modelId, count } of summary.richestModels.slice(0, 5)) {
  }
}
